  FOR UPDATE USING (
    EXISTS (
      SELECT 1 FROM public.users
      WHERE users.id = auth.uid() AND users.role = 'SMS_ADMIN'
    )
  ) WITH CHECK (
    EXISTS (
      SELECT 1 FROM public.users
      WHERE users.id = auth.uid() AND users.role = 'SMS_ADMIN'
    )
  );

CREATE POLICY "Enable delete for admin users only" ON public.service_classifications
  FOR DELETE USING (
    EXISTS (
      SELECT 1 FROM public.users
      WHERE users.id = auth.uid() AND users.role = 'SMS_ADMIN'
    )
  );

