    EXISTS (SELECT 1 FROM public.users WHERE users.id = auth.uid() AND users.role = 'SMS_ADMIN')
);
CREATE POLICY "Enable all for admin" ON public.procedure_cid FOR ALL USING (
    EXISTS (SELECT 1 FROM public.users WHERE users.id = auth.uid() AND users.role = 'SMS_ADMIN')
);

